selector-no-redundant-nesting-selector */\n\n/// Grid system\n//\n// Generate semantic grid columns with these mixins.\n\n@use 'sass:math';\n\n@mixin make-container($gutter: $grid-gutter-width) {\n  box-sizing: border-box;\n  margin-left: auto;\n  margin-right: auto;\n  padding-left: math.div($gutter, 2);\n  padding-right: math.div($gutter, 2);\n  width: 100%;\n}\n\n// For each breakpoint, define the maximum width of the container in a media query\n@mixin make-container-max-widths(\n  $max-widths: $container-max-widths,\n  $breakpoints: $grid-breakpoints\n) {\n  @each $breakpoint, $container-max-width in $max-widths {\n    @include media-breakpoint-up($breakpoint, $breakpoints) {\n      max-width: $container-max-width;\n    }\n  }\n}\n\n@mixin make-col($size, $columns: $grid-columns) {\n  box-sizing: border-box;\n  flex: 0 0 percentage(math.div($size, $columns));\n  // Add a `max-width` to ensure content within each column does not blow out\n  // the width of the column. Applies to IE10+ and Firefox. Chrome and Safari\n  // do not appear to require this.\n  max-width: percentage(math.div($size, $columns));\n}\n\n@mixin make-row($gutter: $grid-gutter-width) {\n  box-sizing: border-box;\n  display: flex;\n  flex-wrap: wrap;\n  margin-left: math.div(-$gutter, 2);\n  margin-right: math.div(-$gutter, 2);\n}\n\n@mixin make-col-offset($size, $columns: $grid-columns) {\n  $num: math.div($size, $columns);\n  box-sizing: border-box;\n  margin-left: if($num == 0, 0, percentage($num));\n}\n\n// Row columns\n//\n// Specify on a parent element(e.g., .row) to force immediate children into NN\n// numberof columns. Supports wrapping to new lines, but does not do a Masonry\n// style grid.\n\n@mixin row-cols($count) {\n  & > * {\n    box-sizing: border-box;\n    flex: 0 0 math.div(100%, $count);\n    max-width: math.div(100%, $count);\n  }\n}\n\n@mixin make-row-columns($breakpoints: $grid-breakpoints) {\n  @each $breakpoint in map-keys($breakpoints) {\n    $infix: breakpoint-infix($breakpoint, $breakpoints);\n\n    @include media-breakpoint-up($breakpoint, $breakpoints) {\n      @if $grid-row-columns > 0 {\n        @for $i from 1 through $grid-row-columns {\n          .ods-row-cols#{$infix}-#{$i} {\n            @include row-cols($i);\n          }\n        }\n      }\n    }\n  }\n}\n\n// Columns\n//\n// Used only by Bootstrap to generate the correct number of grid classes given\n// any value of `$grid-columns`.\n\n@mixin make-grid-columns(\n  $columns: $grid-columns,\n  $gutter: $grid-gutter-width,\n  $breakpoints: $grid-breakpoints\n) {\n  // Common properties for all breakpoints\n  %grid-column {\n    box-sizing: border-box;\n    padding-left: math.div($gutter, 2);\n    padding-right: math.div($gutter, 2);\n    position: relative;\n    width: 100%;\n  }\n\n  @each $breakpoint in map-keys($breakpoints) {\n    $infix: breakpoint-infix($breakpoint, $breakpoints);\n\n    @if $columns > 0 {\n      // Allow columns to stretch full width below their breakpoints\n      @for $i from 1 through $columns {\n        .ods-col#{$infix}-#{$i} {\n          @extend %grid-column;\n        }\n      }\n    }\n\n    .ods-col#{$infix},\n    .ods-col#{$infix}-auto {\n      @extend %grid-column;\n    }\n\n    /* stylelint-disable-next-line order/order */\n    @include media-breakpoint-up($breakpoint, $breakpoints) {\n      // Provide basic `.ods-col-{bp}` classes for equal-width flexbox columns\n      .ods-col#{$infix} {\n        box-sizing: border-box;\n        flex-basis: 0;\n        flex-grow: 1;\n        max-width: 100%;\n        min-width: 0;\n      }\n\n      .ods-col#{$infix}-auto {\n        box-sizing: border-box;\n        flex: 0 0 auto;\n        max-width: 100%; // Reset earlier grid tiers\n        width: auto;\n      }\n\n      @if $columns > 0 {\n        @for $i from 1 through $columns {\n          .ods-col#{$infix}-#{$i} {\n            @include make-col($i, $columns);\n          }\n        }\n      }\n\n      @if $columns > 0 {\n        // `$columns - 1` because offsetting by the width of an entire row isn't possible\n        @for $i from 0 through ($columns - 1) {\n          @if not($infix == '' and $i == 0) {\n            // Avoid emitting useless .offset-0\n            .ods-offset#{$infix}-#{$i} {\n              @include make-col-offset($i, $columns);\n            }\n          }\n        }\n      }\n    }\n  }\n}\n","/* stylelint-disable scss/at-extend-no-missing-placeholder */\n\n// Single container class with breakpoint max-widths\n.ods-container {\n  @include make-container();\n  @include make-container-max-widths();\n}\n\n// 100% wide container at all breakpoints\n.ods-container-fluid {\n  @include make-container();\n}\n\n// Responsive containers that are 100% wide until a breakpoint\n@each $breakpoint, $container-max-width in $container-max-widths {\n  .ods-container-#{$breakpoint} {\n    @extend .ods-container-fluid;\n  }\n\n  /* stylelint-disable-next-line order/order */\n  @include media-breakpoint-up($breakpoint, $grid-breakpoints) {\n    // Extend each breakpoint which is smaller or equal to the current breakpoint\n    $extend-breakpoint: true;\n\n    %responsive-container-#{$breakpoint} {\n      max-width: $container-max-width;\n    }\n\n    @each $name, $width in $grid-breakpoints {\n      @if ($extend-breakpoint) {\n        .ods-container#{breakpoint-infix($name, $grid-breakpoints)} {\n          @extend %responsive-container-#{$breakpoint};\n        }\n\n        // Once the current breakpoint is reached, stop extending\n        /* stylelint-disable-next-line max-nesting-depth */\n        @if ($breakpoint == $name) {\n          $extend-breakpoint: false;\n        }\n      }\n    }\n  }\n}\n",'/* stylelint-disable max-nesting-depth, scss/selector-no-redundant-nesting-selector */\n/* stylelint-disable scss/at-extend-no-missing-placeholder */\n.ods-container {\n  box-sizing: border-box;\n  margin-left: auto;\n  margin-right: auto;\n  padding-left: 8px;\n  padding-right: 8px;\n  width: 100%;\n}\n@media (min-width: 576px) {\n  .ods-container {\n    max-width: 540px;\n  }\n}\n@media (min-width: 768px) {\n  .ods-container {\n    max-width: 720px;\n  }\n}\n@media (min-width: 992px) {\n  .ods-container {\n    max-width: 960px;\n  }\n}\n@media (min-width: 1200px) {\n  .ods-container {\n    max-width: 1140px;\n  }\n}\n\n.ods-container-fluid, .ods-container-xl, .ods-container-lg, .ods-container-md, .ods-container-sm {\n  box-sizing: border-box;\n  margin-left: auto;\n  margin-right: auto;\n  padding-left: 8px;\n  padding-right: 8px;\n  width: 100%;\n}\n\n/* stylelint-disable-next-line order/order */\n@media (min-width: 576px) {\n  .ods-container-sm, .ods-container {\n    max-width: 540px;\n  }\n\n  /* stylelint-disable-next-line max-nesting-depth */\n  /* stylelint-disable-next-line max-nesting-depth */\n}\n/* stylelint-disable-next-line order/order */\n@media (min-width: 768px) {\n  .ods-container-md, .ods-container-sm, .ods-container {\n    max-width: 720px;\n  }\n\n  /* stylelint-disable-next-line max-nesting-depth */\n  /* stylelint-disable-next-line max-nesting-depth */\n  /* stylelint-disable-next-line max-nesting-depth */\n}\n/* stylelint-disable-next-line order/order */\n@media (min-width: 992px) {\n  .ods-container-lg, .ods-container-md, .ods-container-sm, .ods-container {\n    max-width: 960px;\n  }\n\n  /* stylelint-disable-next-line max-nesting-depth */\n  /* stylelint-disable-next-line max-nesting-depth */\n  /* stylelint-disable-next-line max-nesting-depth */\n  /* stylelint-disable-next-line max-nesting-depth */\n}\n/* stylelint-disable-next-line order/order */\n@media (min-width: 1200px) {\n  .ods-container-xl, .ods-container-lg, .ods-container-md, .ods-container-sm, .ods-container {\n    max-width: 1140px;\n  }\n\n  /* stylelint-disable-next-line max-nesting-depth */\n  /* stylelint-disable-next-line max-nesting-depth */\n  /* stylelint-disable-next-line max-nesting-depth */\n  /* stylelint-disable-next-line max-nesting-depth */\n  /* stylelint-disable-next-line max-nesting-depth */\n}\n.ods-row {\n  box-sizing: border-box;\n  display: flex;\n  flex-wrap: wrap;\n  margin-left: -8px;\n  margin-right: -8px;\n}\n\n.ods-row-cols-1 > * {\n  box-sizing: border-box;\n  flex: 0 0 100%;\n  max-width: 100%;\n}\n\n.ods-row-cols-2 > * {\n  box-sizing: border-box;\n  flex: 0 0 50%;\n  max-width: 50%;\n}\n\n.ods-row-cols-3 > * {\n  box-sizing: border-box;\n  flex: 0 0 33.3333333333%;\n  max-width: 33.3333333333%;\n}\n\n.ods-row-cols-4 > * {\n  box-sizing: border-box;\n  flex: 0 0 25%;\n  max-width: 25%;\n}\n\n.ods-row-cols-5 > * {\n  box-sizing: border-box;\n  flex: 0 0 20%;\n  max-width: 20%;\n}\n\n.ods-row-cols-6 > * {\n  box-sizing: border-box;\n  flex: 0 0 16.6666666667%;\n  max-width: 16.6666666667%;\n}\n\n@media (min-width: 576px) {\n  .ods-row-cols-sm-1 > * {\n    box-sizing: border-box;\n    flex: 0 0 100%;\n    max-width: 100%;\n  }\n\n  .ods-row-cols-sm-2 > * {\n    box-sizing: border-box;\n    flex: 0 0 50%;\n    max-width: 50%;\n  }\n\n  .ods-row-cols-sm-3 > * {\n    box-sizing: border-box;\n    flex: 0 0 33.3333333333%;\n    max-width: 33.3333333333%;\n  }\n\n  .ods-row-cols-sm-4 > * {\n    box-sizing: border-box;\n    flex: 0 0 25%;\n    max-width: 25%;\n  }\n\n  .ods-row-cols-sm-5 > * {\n    box-sizing: border-box;\n    flex: 0 0 20%;\n    max-width: 20%;\n  }\n\n  .ods-row-cols-sm-6 > * {\n    box-sizing: border-box;\n    flex: 0 0 16.6666666667%;\n    max-width: 16.6666666667%;\n  }\n}\n@media (min-width: 768px) {\n  .ods-row-cols-md-1 > * {\n    box-sizing: border-box;\n    flex: 0 0 100%;\n    max-width: 100%;\n  }\n\n  .ods-row-cols-md-2 > * {\n    box-sizing: border-box;\n    flex: 0 0 50%;\n    max-width: 50%;\n  }\n\n  .ods-row-cols-md-3 > * {\n    box-sizing: border-box;\n    flex: 0 0 33.3333333333%;\n    max-width: 33.3333333333%;\n  }\n\n  .ods-row-cols-md-4 > * {\n    box-sizing: border-box;\n    flex: 0 0 25%;\n    max-width: 25%;\n  }\n\n  .ods-row-cols-md-5 > * {\n    box-sizing: border-box;\n    flex: